input = sys.stdin.readline

def solve():
    input()  # empty line
    n, k = map(int, input().split())
    mines = []
    for _ in range(n):
        x, y, t = map(int, input().split())
        mines.append((x, y, t))

    parent = list(range(n))
    rank = [0] * n

    def find(a):
        while parent[a] != a:
            parent[a] = parent[parent[a]]
            a = parent[a]
        return a

    def union(a, b):
        a, b = find(a), find(b)
        if a == b: return
        if rank[a] < rank[b]: a, b = b, a
        parent[b] = a
        if rank[a] == rank[b]: rank[a] += 1

    # Group by x, sort by y
    by_x = defaultdict(list)
    for i, (x, y, t) in enumerate(mines):
        by_x[x].append((y, i))

    for x, lst in by_x.items():
        lst.sort()
        for j in range(1, len(lst)):
            if lst[j][0] - lst[j-1][0] <= k:
                union(lst[j][1], lst[j-1][1])

