    # Find min timer per component
    comp_min = {}
    for i, (x, y, t) in enumerate(mines):
        r = find(i)
        if r not in comp_min:
            comp_min[r] = t
        else:
            comp_min[r] = min(comp_min[r], t)

    timers = sorted(comp_min.values())

    # Binary search on T
    # For given T: components needing manual detonation = those with min_timer > T
    # Need count <= T + 1
    import bisect

    lo, hi = 0, max(timers) if timers else 0

    # Check T=0 first possibility
    def check(T):
        # number of components with min_timer > T
        idx = bisect.bisect_right(timers, T)
        need = len(timers) - idx
        return need <= T + 1

    if check(0):
        print(0)
        return

    lo, hi = 0, max(timers)
    while lo < hi:
        mid = (lo + hi) // 2
        if check(mid):
            hi = mid
        else:
            lo = mid + 1

    print(lo)

t = int(input())
for _ in range(t):
    solve()

